THE RISK:
{
 "id": "prelet-pipeline-lockout",
 "title": "83% pre-let pipeline means the Year-1 PDU bill-of-materials is already written by someone else",
 "narrative": "The 3% obtainable factor treats SAM as an open order book. But FLAP-D vacancy is at a record-low 6.3% with the development pipeline 83% pre-let — and in pre-let builds, the electrical BOM including rack PDUs is specified at design/tender, 12–24 months before commissioning, almost always against incumbent framework agreements. A pre-launch entrant's first 12 months therefore address not 'the market' but the thin residue of break-fix replacement, late-stage change orders, and un-spec'd white-space — a flow that supports well under 1% of SAM, consistent with the hardware-entrant analogues (0.1%–0.001%) the corpus surfaced and the model's own crossCheck flagged before settling on 3%.",
 "category": "model-structure",
 "targetNodes": [
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "FLAP-D vacancy hits a record low of 6.3% and the construction pipeline is 83% pre-let — capacity being delivered in 2026 already has committed tenants and, with them, committed electrical vendor stacks",
   "refs": [
    "digest:geo-DE#c21",
    "digest:geo-DE#c20"
   ]
  },
  {
   "step": "propagation",
   "text": "The venture is pre-launch, targeting large operators first; those operators procure rack power against multi-year frameworks with the incumbent top-3 (CR3 ~0.55), so 2026–27 fit-out deliveries are contractually spoken for before the venture can even bid",
   "refs": [
    "profile:Stage",
    "ledger:cust.operator-large",
    "ledger:shape.cr3"
   ]
  },
  {
   "step": "model-impact",
   "text": "obtainableFactor's 3% mid-band is anchored to generic SOM benchmarks, not to the share of the flow that is actually orderable in the window; the pre-let lockout compresses reachable Year-1 demand to replacement and spot buys, well below the band's low end",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "3% looks humble — it sits in the middle of every published Year-1 SOM benchmark, so it reads as conservative. The surface appearance of 'we only need a tiny sliver' hides that share of a market is not share of the orderable flow: when 83% of near-term capacity is pre-let, most of the sliver was awarded before launch day.",
 "expectedObviousness": "low",
 "falsifier": "Two or more CE data-center fit-out tenders with 2026 delivery dates where the rack-PDU line item is still open to new vendors at time of bid (i.e., not pre-committed under a framework), and the venture is admitted to bid.",
 "likelihood": {
  "value": 0.5,
  "rationale": "The 83% pre-let figure and framework-based procurement in large-operator channels are documented; the counterweight is that replacement/retrofit demand in the 56% non-hyperscale base is genuinely spot-purchased, so full lockout is unlikely but material compression is probable. [evidence revision: The 83% pre-let / 6.3% vacancy figures and the pre-commitment-as-primary-route dynamic are now firmly documented by the primary source (JLL) and independent corroborators, strengthening the trigger and propagation steps. The unresolved element remains the magnitude of compression to obtainableFactor — pre-let capacity locks in the fit-out BOM but does not eliminate spot/replacement demand in the installed base, and no direct evidence quantifies the Year-1 orderable residue. Modest upward revision from 0.45 to 0.50 reflects strong confirmation of premises while retaining uncertainty on the model-impact magnitude.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "obtainableFactor",
   "op": "set",
   "value": 0.008,
   "note": "Year-1 orderable flow limited to replacement, change orders, and un-spec'd white-space — below the modeled 1–5% band for reasons the band does not contemplate"
  }
 ],
 "indicators": [
  {
   "signal": "Share of CE fit-out RFQs where rack-PDU vendor is open vs pre-specified",
   "where": "TED (EU tender portal) and operator supplier portals (Equinix, NTT, Data4 RFQ postings)",
   "threshold": "<20% of 2026-delivery RFQs with open PDU line items",
   "updates": "increases"
  },
  {
   "signal": "Pre-let ratio of the FLAP-D and CE pipeline",
   "where": "JLL EMEA data centre report (semi-annual)",
   "threshold": "Pre-let staying ≥80% through 2026",
   "updates": "increases"
  },
  {
   "signal": "Incumbent backlog commentary on rack power",
   "where": "Vertiv and Schneider quarterly earnings calls",
   "threshold": "Backlog coverage extending beyond 12 months",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Run structured interviews with 3 CE colo/hyperscale procurement leads specifically on WHEN in the build cycle PDU vendors are locked and what share of spend is spot-purchased",
   "type": "information",
   "voiNodeId": "obtainableFactor",
   "note": "Converts the 1–5% generic benchmark into a flow-based, CE-specific obtainable model"
  },
  {
   "action": "Re-aim the Year-1 motion at replacement/retrofit and white-space expansion in operating colo halls, where PDU purchasing is not gated by pre-let frameworks",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Sells into the only genuinely open segment of the Year-1 flow"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "EMEA year end data centre report 2025",
   "sourceType": "industry-report",
   "publisher": "JLL",
   "date": "2026-03-30",
   "excerpt": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced. Pre-commitment is now the only viable route to securing meaningful capacity across Europe.",
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "attached": true
  },
  {
   "title": "Data centre vacancy hits record low as demand outstrips supply",
   "sourceType": "triangulation",
   "publisher": "Estates Gazette",
   "date": "2026-04-09",
   "excerpt": "around 83% of space currently under construction already pre-let... pre-leasing now the primary route to securing capacity... large occupiers increasingly forced to commit to space well ahead of delivery.",
   "url": "https://www.estatesgazette.co.uk/news/data-centre-vacancy-hits-record-low-as-demand-outstrips-supply/",
   "attached": true
  },
  {
   "title": "Supply Chain and Technology Agreements in Data Center Construction",
   "sourceType": "industry-report",
   "publisher": "Bracewell LLP / JDSupra",
   "date": "2026-01-27",
   "excerpt": "data center operators are increasingly relying on robust supply chain and technology agreements that include component shortage remedies, price adjustment clauses, alternative sourcing clauses",
   "url": "https://www.jdsupra.com/legalnews/supply-chain-and-technology-agreements-1931379/",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "stance": "supports",
   "quote": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced. Pre-commitment is now the only viable route to securing meaningful capacity across Europe."
  },
  {
   "url": "https://datacentrereview.com/2026/04/emea-data-centre-vacancy-hits-record-low-as-ai-demand-outpaces-supply/",
   "stance": "supports",
   "quote": "vacancy rates at the end of 2025 across the FLAP-D markets of Frankfurt, London, Amsterdam, Paris and Dublin fell to a record low of 6.3% in Q4 2025... 83% of the pipeline is already pre-let, underlining just how difficult it is becoming for occupiers to secure meaningful capacity"
  },
  {
   "url": "https://www.estatesgazette.co.uk/news/data-centre-vacancy-hits-record-low-as-demand-outstrips-supply/",
   "stance": "supports",
   "quote": "with around 83% of space currently under construction already pre-let, underlining the depth of occupier demand. This tightening supply-demand dynamic is reshaping how occupiers access space, with pre-leasing now the primary route to securing capacity."
  },
  {
   "url": "https://www.jdsupra.com/legalnews/supply-chain-and-technology-agreements-1931379/",
   "stance": "supports",
   "quote": "data center operators are increasingly relying on robust supply chain and technology agreements that include component shortage remedies, price adjustment clauses, alternative sourcing clauses"
  },
  {
   "url": "https://thenextweb.com/news/china-telecom-server-deal-huawei-kunpeng-1-7bn",
   "stance": "supports",
   "quote": "Huawei did not even bid, yet its ecosystem walked away with the bulk of the deal. That is not an accident. It is the template."
  },
  {
   "url": "https://www.tendersinfo.com/global-data-center-equipment-tenders.php",
   "stance": "silent",
   "quote": "Data Center Equipment tenders are published by government departments, public sector organizations, infrastructure authorities, international agencies, and private companies"
  }
 ]
}

